/**
 * `flush()` operation.
 *
 * Async operation: returns request ID, poll with `pollFlush()`
 */
export function flush(self: bigint): void {
  const requestId = _nextAsyncHandle++;
  const obj = getWebGlRenderingContextBase(self);
  const promise = obj.flush()
    .then((result) => {
      const entry = _asyncHandles.get(requestId);
      if (entry) {
        entry.result = { ok: true };
      }
    })
    .catch((err: Error) => {
      const entry = _asyncHandles.get(requestId);
      if (entry) {
        entry.result = { ok: false, error: err.message };
      }
    });

  _asyncHandles.set(requestId, { promise, result: null });
  return requestId;
}

/**
 * Poll an async `flush()` operation.
 * Returns undefined if still pending, or the result if complete.
 */
export function pollFlush(requestId: bigint): { ok: true } | { ok: false; error: string } | undefined {
  const entry = _asyncHandles.get(requestId);
  if (!entry) {
    return { ok: false, error: `Unknown request ID ${requestId}` };
  }
  return entry.result ?? undefined;
}

